            pass

    # XML: processing instruction, doctype, or tag start
    if s.startswith('<?xml') or s.startswith('<!DOCTYPE') or re.match(r'^<[a-zA-Z_/?][^>]*>', s):
        return 'xml'

    # PHP serialized data (unsafe)
    if re.match(r'^(a|O|s|i|b|d):\d+:', s) or s.startswith('N;'):
